function validTicTacToe(board) {
    let xCount = 0, oCount = 0;
    for (const row of board) {
        for (const c of row) {
            if (c === 'X') xCount++;
            else if (c === 'O') oCount++;
        }
    }
    if (xCount !== oCount && xCount !== oCount + 1) return false;

    let xWin = false, oWin = false;
    for (let i = 0; i < 3; ++i) {
        if (board[i][0] === board[i][1] && board[i][1] === board[i][2])
            board[i][0] === 'X' ? xWin = true : (board[i][0] === 'O' ? oWin = true : 0);
        if (board[0][i] === board[1][i] && board[1][i] === board[2][i])
            board[0][i] === 'X' ? xWin = true : (board[0][i] === 'O' ? oWin = true : 0);
    }
    if (board[0][0] === board[1][1] && board[1][1] === board[2][2])
        board[0][0] === 'X' ? xWin = true : (board[0][0] === 'O' ? oWin = true : 0);
    if (board[0][2] === board[1][1] && board[1][1] === board[2][0])
        board[0][2] === 'X' ? xWin = true : (board[0][2] === 'O' ? oWin = true : 0);

    if (xWin && oWin) return false;
    if (xWin && xCount === oCount) return false;
    if (oWin && xCount > oCount) return false;

    return true;
}
```


    First, count the number of X's and O's. If the difference between the counts is not 0 or 1, return false.

Then, check if X or O has won (formed a 3-length line in a row, column, or diagonal).
1. Iterate through each row and column checking for three in a row (a win).
2. Check the two diagonals for a win.

After checking for wins, there are three invalid cases:
1. Both X and O have won (not possible in a valid game).
2. X has won, but there are an equal number of X's and O's on the board.
3. O has won, but there are more X's than O's on the board.

If none of these cases apply, return true.

